    public static long solve(long n, long[][] edges, long k) {
        // Sort edges by weight
        Arrays.sort(edges, (a, b) -> Long.compare(a[2], b[2]));

        // Union-Find data structure
        UnionFind uf = new UnionFind(n);

        // Track the maximum weight in each component
        Map<Long, Long> maxWeightMap = new HashMap<>();

        // Initialize maxWeightMap with each node as its own component
        for (long i = 0; i < n; i++) {
            maxWeightMap.put(i, 0L);
        }

        // Process edges in order of increasing weight
        for (long[] edge : edges) {
            long u = edge[0];
            long v = edge[1];
            long w = edge[2];

            long rootU = uf.find(u);
            long rootV = uf.find(v);

            if (rootU != rootV) {
                // Merge the two components
                uf.union(rootU, rootV);

                // Update the max weight of the new component
                long newMaxWeight = Math.max(maxWeightMap.get(rootU), maxWeightMap.get(rootV));
                newMaxWeight = Math.max(newMaxWeight, w);
                maxWeightMap.put(rootV, newMaxWeight);
            }
        }

        // Find the maximum weight among all components
        long result = 0;
        for (long weight : maxWeightMap.values()) {
            result = Math.max(result, weight);
        }

        return result;
    }

